package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"path/filepath"
	"regexp"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
)

// ExecuteBeadLoopRuntime carries the non-serializable plumbing and
// per-invocation runtime intent for an execute-bead loop run. Durable knobs
// (assignee, retry caps, harness/model, tier bounds, etc.) live on
// config.ResolvedConfig and are passed via Run's rcfg argument.
type ExecuteBeadLoopRuntime struct {
	Log          io.Writer
	EventSink    io.Writer
	ProgressCh   chan<- ProgressEvent
	PreClaimHook func(ctx context.Context) error
	// RoutePreflight, when non-nil, is invoked between nextCandidate and
	// Claim. It is expected to call upstream ResolveRoute against the
	// loop's resolved (harness, model) and return whatever typed routing
	// error the upstream surfaced — notably agent.ErrHarnessModelIncompatible
	// when the harness allow-list rejects the model. Any non-nil error
	// causes the loop to exit immediately without claiming the bead, with
	// a worker-level execution_failed record naming the rejected pair.
	// DDx does NOT duplicate the upstream allow-list; this gate only
	// consumes the typed-incompatibility surface.
	RoutePreflight func(ctx context.Context, harness, model string) error
	Once           bool
	PollInterval   time.Duration
	NoReview       bool
	LabelFilter    string
	SessionID      string
	WorkerID       string
	ProjectRoot    string
	// TargetBeadID, when non-empty, restricts nextCandidate to only return the
	// named bead from the execution-ready queue. Used by `ddx try <bead-id>`
	// to dispatch a single specific bead through the same claim → executor →
	// land path the queue drain uses. When empty, the picker behaves normally.
	TargetBeadID string
	// WakeCh, when non-nil, signals the idle-poll sleep to return immediately
	// so the loop re-scans the queue. Used by the operator-prompt approve /
	// auto-approve mutations (Story 15) to avoid a poll-interval-sized delay
	// before a freshly-approved bead is claimed. Implementations must send
	// non-blocking (server-side helpers do); the loop only waits for a
	// receive on WakeCh during the idle sleep, never elsewhere.
	WakeCh <-chan struct{}
}

// DefaultReviewMaxRetries is the number of reviewer attempts allowed per
// committed result_rev before the loop emits a terminal
// `review-manual-required` event and stops re-executing primary. FEAT-022 §14.
const DefaultReviewMaxRetries = 3

// MaxLoopCooldown is the absolute upper bound the execute-loop will set for
// any execute-loop-retry-after value. Year-scale parks effectively mean
// "never retry" and that should be a deliberate operator choice via
// `ddx bead update --set execute-loop-retry-after=...`, not an automatic
// loop decision. Beyond this cap, the loop refuses to lengthen the cooldown
// further; an operator extending it manually still works.
const MaxLoopCooldown = 24 * time.Hour

// LandConflictCooldown is the short cooldown applied when all conflict-recovery
// paths fail (3-way ort auto-merge + optional focused-resolve agent) and the
// bead is parked as land_conflict_unresolvable. Much shorter than
// MaxLoopCooldown because land conflicts often resolve quickly as sibling beads
// advance the base branch.
const LandConflictCooldown = 15 * time.Minute

// StoreErrorCooldown is the short cooldown applied when a Store.* operation in
// the outcome-handling block returns a transient error. It prevents an
// immediate re-queue of the affected bead while allowing the loop to continue
// to the next candidate. Store errors during outcome handling are non-fatal:
// they are logged and emitted as loop-error events but do not terminate the
// worker.
const StoreErrorCooldown = 5 * time.Minute

// SubmitWithPreMergeChecks is the canonical land-back step for the execute-bead
// loop. It runs the project's .ddx/checks/*.yaml gate against the worker's
// (baseRev, resultRev) before forwarding to submit. On Blocked, it preserves
// the worker's result under refs/ddx/iterations/, records checks-blocked
// events on the bead, and returns the synthesised LandResult{Status:"preserved"}
// without ever calling submit. On pass, honoured checks-bypass annotations are
// recorded as checks-bypass events and submit runs normally.
//
// submit is the project's land coordinator entry point (typically
// LocalLandCoordinator.Submit or the server-side coordinator submit).
//
// The implementation lives in checks_premerge.go alongside its supporting
// helpers (RunPreMergeChecks, AppendPreMergeChecksEvents,
// PreserveAfterPreMergeChecks); this thin wrapper exists so the execute-bead
// loop's land-back call site is one obvious helper rather than three nested
// ones, and so callers wiring the gate do not need to import the helper layer
// directly.
func SubmitWithPreMergeChecks(
	ctx context.Context,
	projectRoot string,
	b *bead.Bead,
	res *ExecuteBeadResult,
	submit func(LandRequest) (*LandResult, error),
	eventStore BeadEventAppender,
	actor, source string,
	now func() time.Time,
) (*LandResult, *PreMergeChecksOutcome, error) {
	if now == nil {
		now = time.Now
	}
	if submit == nil {
		return nil, nil, fmt.Errorf("submit-with-pre-merge-checks: submit callback required")
	}
	evidenceDir := filepath.Join(projectRoot, res.ExecutionDir)
	outcome, err := RunPreMergeChecks(ctx, projectRoot, b, res.BaseRev, res.ResultRev, evidenceDir)
	if err != nil {
		// Treat checks_bypass / loader errors as a hard preserve: the worker
		// did its job; the operator misconfigured the gate. Better to park
		// the result under an iteration ref than to silently land it.
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if upErr := (&RealOrchestratorGitOps{}).UpdateRef(projectRoot, ref, res.ResultRev); upErr != nil {
			return nil, nil, fmt.Errorf("preserving result after checks setup error: %w (original error: %v)", upErr, err)
		}
		return &LandResult{
			Status:      "preserved",
			PreserveRef: ref,
			Reason:      "pre-merge checks setup error: " + err.Error(),
		}, nil, nil
	}
	if outcome.Blocked {
		land, perr := PreserveAfterPreMergeChecks(projectRoot, res, outcome, &RealOrchestratorGitOps{})
		if perr != nil {
			return nil, outcome, perr
		}
		if eventStore != nil {
			_ = AppendPreMergeChecksEvents(eventStore, res.BeadID, outcome, actor, source, now().UTC())
		}
		return land, outcome, nil
	}
	if eventStore != nil && len(outcome.Bypassed) > 0 {
		_ = AppendPreMergeChecksEvents(eventStore, res.BeadID, outcome, actor, source, now().UTC())
	}
	land, sErr := submit(BuildLandRequestFromResult(projectRoot, res))
	return land, outcome, sErr
}

// handleOutcomeStoreError is called when a Store.* operation in the
// post-Execute outcome block returns a non-nil error. It logs the error,
// appends a kind:loop-error event to the bead (best-effort), sets a short
// cooldown so the bead is not immediately re-queued, increments
// result.Failures, and returns true — signalling the caller to continue to
// the next loop iteration rather than returning.
//
// If ctx is already cancelled, it returns false so the caller can propagate
// the cancellation immediately.
func (w *ExecuteBeadWorker) handleOutcomeStoreError(ctx context.Context, beadID, operation string, storeErr error, assignee string, result *ExecuteBeadLoopResult, runtime ExecuteBeadLoopRuntime, now func() time.Time) bool {
	if ctx.Err() != nil {
		return false
	}
	if runtime.Log != nil {
		_, _ = fmt.Fprintf(runtime.Log, "outcome store error (%s %s): %v (continuing)\n", operation, beadID, storeErr)
	}
	_ = w.Store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "loop-error",
		Summary:   operation + " failed",
		Body:      storeErr.Error(),
		Actor:     assignee,
		Source:    "ddx agent execute-loop",
		CreatedAt: now().UTC(),
	})
	cooldownUntil := now().UTC().Add(StoreErrorCooldown)
	_ = w.Store.SetExecutionCooldown(beadID, cooldownUntil, "loop-error", operation+": "+storeErr.Error())
	result.Failures++
	result.LastFailureStatus = "loop-error"
	return true
}

// CapLoopCooldown clamps a loop-set cooldown duration to MaxLoopCooldown.
// The loop uses this for every SetExecutionCooldown call so no automatic
// path can silently park a bead for a year.
func CapLoopCooldown(d time.Duration) time.Duration {
	if d <= 0 {
		return 0
	}
	if d > MaxLoopCooldown {
		return MaxLoopCooldown
	}
	return d
}

type ExecuteBeadReport struct {
	BeadID    string `json:"bead_id"`
	AttemptID string `json:"attempt_id,omitempty"`
	WorkerID  string `json:"worker_id,omitempty"`
	Harness   string `json:"harness,omitempty"`
	Provider  string `json:"provider,omitempty"`
	Model     string `json:"model,omitempty"`
	// ActualPower is the routing-decision power of the model that actually
	// served the implementer's call. Forwarded to the post-merge reviewer so
	// it can request MinPower=actualPower+1 and bias routing toward a
	// stronger reviewer (R4 pairing).
	ActualPower int    `json:"actual_power,omitempty"`
	Status      string `json:"status"`
	Detail      string `json:"detail,omitempty"`
	SessionID   string `json:"session_id,omitempty"`
	BaseRev     string `json:"base_rev,omitempty"`
	ResultRev   string `json:"result_rev,omitempty"`
	PreserveRef string `json:"preserve_ref,omitempty"`
	RetryAfter  string `json:"retry_after,omitempty"`
	// NoChangesRationale carries the agent's explanation when status == no_changes.
	NoChangesRationale string `json:"no_changes_rationale,omitempty"`
	// ReviewVerdict is the post-merge review verdict (APPROVE, REQUEST_CHANGES,
	// or BLOCK) when a reviewer ran. Empty when review was skipped.
	ReviewVerdict string `json:"review_verdict,omitempty"`
	// ReviewRationale carries the actionable reviewer-authored findings for
	// non-APPROVE review outcomes.
	ReviewRationale string `json:"review_rationale,omitempty"`
	// Tier is the model tier used for the final attempt (cheap, standard, smart).
	// Populated by tier-escalating executors; empty for single-tier attempts.
	Tier string `json:"tier,omitempty"`
	// ProbeResult is a brief summary of the provider health probe at attempt time.
	ProbeResult string `json:"probe_result,omitempty"`
	// CostUSD is the dollar cost of this attempt as reported by the harness.
	// Tier-escalating executors propagate this so the escalation trace can
	// compute wasted/effective spend.
	CostUSD float64 `json:"cost_usd,omitempty"`
	// DurationMS is the wall-clock duration of this attempt.
	DurationMS int64 `json:"duration_ms,omitempty"`
	// Profile routing telemetry. Populated when execute-loop uses a profile
	// ladder rather than an explicit harness/model pin.
	RequestedProfile string `json:"requested_profile,omitempty"`
	RequestedTier    string `json:"requested_tier,omitempty"`
	ResolvedTier     string `json:"resolved_tier,omitempty"`
	EscalationCount  int    `json:"escalation_count,omitempty"`
	FinalTier        string `json:"final_tier,omitempty"`
	// DecompositionRecommendation carries the structured list of recommended
	// sub-bead titles when Status == declined_needs_decomposition. The loop
	// records these on the bead as a `decomposition-recommendation` event so
	// operators (or helix-evolve) can split the bead without re-deriving the
	// recommendation.
	DecompositionRecommendation []string `json:"decomposition_recommendation,omitempty"`
	// DecompositionRationale is a free-form explanation accompanying
	// DecompositionRecommendation. Optional.
	DecompositionRationale string `json:"decomposition_rationale,omitempty"`
	// Disrupted marks a failed attempt as worker-disrupted rather than
	// model-gave-up: the model was prevented from making progress by an
	// external cause (context cancellation, executor SIGKILL/SIGTERM,
	// transport-class provider error, server restart, routing preflight
	// rejection). The execute-loop bypasses the no-progress cooldown for
	// Disrupted reports so the bead is immediately re-claimable instead of
	// being parked for hours on a transient outage. ddx-5b3e57f4.
	Disrupted bool `json:"disrupted,omitempty"`
	// DisruptionReason carries the kind of disruption detected when
	// Disrupted=true (e.g. "context_canceled", "context_deadline",
	// "transport_error", "preflight_rejected"). Used in the
	// `disruption_detected` event body so operators can see which class is
	// occurring.
	DisruptionReason string `json:"disruption_reason,omitempty"`
}

type ExecuteBeadExecutor interface {
	Execute(ctx context.Context, beadID string) (ExecuteBeadReport, error)
}

type ExecuteBeadExecutorFunc func(ctx context.Context, beadID string) (ExecuteBeadReport, error)

func (f ExecuteBeadExecutorFunc) Execute(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
	return f(ctx, beadID)
}

// SatisfactionChecker evaluates whether a bead that returned no_changes is
// already satisfied and should be closed, or is still unresolved and should
// receive retry suppression. noChangesCount is the cumulative count including
// the current attempt.

package bead

import (
	"encoding/json"
	"fmt"
	"strings"
)

// ChecksBypassExtraKey is the bead.Extra key under which the checks_bypass
// annotation is persisted. The value is a JSON array of objects matching
// ChecksBypassEntry. Stored under Extra (not a dedicated struct field) so
// schema-unaware tools (bd, br, JSON dumps) round-trip the field unchanged.
const ChecksBypassExtraKey = "checks_bypass"

// ChecksBypassEntry skips one named pre-merge check for one bead. Each entry
// MUST carry a non-empty reason — bypasses without justification are rejected
// loudly by ChecksBypasses below so a check cannot be silently disabled.
//
// Bead is optional and serves as a cross-reference (for example, the bead ID
// where the bypass is being tracked for later removal).
type ChecksBypassEntry struct {
	Name   string `json:"name"`
	Reason string `json:"reason"`
	Bead   string `json:"bead,omitempty"`
}

// ChecksBypasses parses the checks_bypass annotation from a bead's Extra map.
// Returns (nil, nil) when no annotation is present. Returns a non-nil error
// when the annotation exists but is malformed, has an entry with an empty
// name, or has an entry with an empty/whitespace-only reason. Empty reasons
// are rejected loudly per the slice contract: a check cannot be bypassed
// without recording why.
func ChecksBypasses(b *Bead) ([]ChecksBypassEntry, error) {
	if b == nil || b.Extra == nil {
		return nil, nil
	}
	raw, ok := b.Extra[ChecksBypassExtraKey]
	if !ok || raw == nil {
		return nil, nil
	}
	// Re-marshal then unmarshal to convert the generic any tree (which json
	// unmarshalled into map[string]any) into a typed slice without writing a
	// custom walker.
	encoded, err := json.Marshal(raw)
	if err != nil {
		return nil, fmt.Errorf("checks_bypass: re-marshal: %w", err)
	}
	var entries []ChecksBypassEntry
	if err := json.Unmarshal(encoded, &entries); err != nil {
		return nil, fmt.Errorf("checks_bypass: must be a JSON array of {name,reason,bead?}: %w", err)
	}
	for i, e := range entries {
		if strings.TrimSpace(e.Name) == "" {
			return nil, fmt.Errorf("checks_bypass[%d]: missing required field: name", i)
		}
		if strings.TrimSpace(e.Reason) == "" {
			return nil, fmt.Errorf("checks_bypass[%d] (%s): missing required field: reason — bypasses must record why the check is being skipped", i, e.Name)
		}
	}
	return entries, nil
}

package agent

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/checks"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
)

// PreMergeChecksDir is the project-relative directory scanned for check
// definitions before each land-back attempt.
const PreMergeChecksDir = ".ddx/checks"

// PreMergeChecksEvidenceSubdir is the per-attempt subdirectory under the
// execution evidence dir into which check result files (one JSON per check)
// are written.
const PreMergeChecksEvidenceSubdir = "checks"

// PreMergeChecksOutcome captures everything callers need to (a) decide
// whether to land or preserve and (b) record events on the bead.
type PreMergeChecksOutcome struct {
	// Results is the per-check outcome for every check that actually ran
	// (post-AppliesTo filter, post-bypass filter). Empty when no checks
	// applied.
	Results []checks.Result
	// Bypassed lists checks_bypass entries that took effect (i.e. matched a
	// loaded check by name and were honoured for this run). Each entry is
	// recorded as a `checks-bypass` event by AppendPreMergeChecksEvents.
	Bypassed []bead.ChecksBypassEntry
	// Blocked is true when at least one applicable, non-bypassed check
	// returned status=block or status=error. The caller MUST NOT land the
	// worker's result when Blocked is true; PreserveAfterPreMergeChecks
	// performs the canonical preservation + event-record dance.
	Blocked bool
	// BlockingNames lists the names of the checks responsible for Blocked=true,
	// sorted alphabetically for stable ordering in evidence.
	BlockingNames []string
	// Reason is a short, human-readable summary suitable for the
	// ExecuteBeadResult.Reason / land Reason field on a preserved outcome.
	Reason string
	// EvidenceDir is the absolute directory where per-check JSON result files
	// were written (the directory the checks runner used as EVIDENCE_DIR).
	EvidenceDir string
}

// RunPreMergeChecks loads all .ddx/checks/*.yaml definitions for the project,
// filters by AppliesTo against the bead's labels and the changed-paths set
// computed from base..result, removes any checks named in the bead's
// checks_bypass annotation, and runs the rest in parallel via checks.Run.
//
// The bead's checks_bypass annotation is validated up front via
// bead.ChecksBypasses; any malformed entry (missing reason, etc.) returns a
// non-nil error so the caller can preserve loudly instead of silently
// honouring an invalid bypass.
//
// evidenceDir is the absolute path to the per-attempt execution evidence
// directory (typically <projectRoot>/.ddx/executions/<run-id>/). Check result
// files are written under evidenceDir/checks/. The directory is created if it
// does not exist.
//
// When the project has no .ddx/checks/ directory or no applicable checks,
// the returned outcome has Blocked=false and empty Results — the caller
// should proceed with the land as if no gate were configured.
func RunPreMergeChecks(ctx context.Context, projectRoot string, b *bead.Bead, baseRev, resultRev, evidenceDir string) (*PreMergeChecksOutcome, error) {
	if projectRoot == "" {
		return nil, fmt.Errorf("pre-merge checks: project_root required")
	}
	if b == nil {
		return nil, fmt.Errorf("pre-merge checks: bead required")
	}

	bypasses, err := bead.ChecksBypasses(b)
	if err != nil {
		return nil, fmt.Errorf("pre-merge checks: invalid checks_bypass annotation: %w", err)
	}

	all, err := checks.LoadDir(filepath.Join(projectRoot, PreMergeChecksDir))
	if err != nil {
		return nil, fmt.Errorf("pre-merge checks: load: %w", err)
	}
	if len(all) == 0 {
		return &PreMergeChecksOutcome{}, nil
	}

	bypassByName := make(map[string]bead.ChecksBypassEntry, len(bypasses))
	for _, e := range bypasses {
		bypassByName[e.Name] = e
	}

	var toRun []checks.Check
	var honouredBypass []bead.ChecksBypassEntry
	for _, c := range all {
		if e, ok := bypassByName[c.Name]; ok {
			honouredBypass = append(honouredBypass, e)
			continue
		}
		toRun = append(toRun, c)
	}

	changed, err := preMergeChangedPaths(projectRoot, baseRev, resultRev)
	if err != nil {
		return nil, fmt.Errorf("pre-merge checks: diff base..result: %w", err)
	}

	checksEvidence := filepath.Join(evidenceDir, PreMergeChecksEvidenceSubdir)
	ictx := checks.InvocationContext{
		BeadID:       b.ID,
		DiffBase:     baseRev,
		DiffHead:     resultRev,
		ProjectRoot:  projectRoot,
		EvidenceDir:  checksEvidence,
		RunID:        newPreMergeRunID(),
		BeadLabels:   b.Labels,
		ChangedPaths: changed,
	}

	results, err := checks.Run(ctx, toRun, ictx)
	if err != nil {
		return nil, fmt.Errorf("pre-merge checks: run: %w", err)
	}

	outcome := &PreMergeChecksOutcome{
		Results:     results,
		Bypassed:    honouredBypass,
		EvidenceDir: checksEvidence,
	}
	for _, r := range results {
		if r.Status == checks.StatusBlock || r.Status == checks.StatusError {
			outcome.Blocked = true
			outcome.BlockingNames = append(outcome.BlockingNames, r.Name)
		}
	}
	if outcome.Blocked {
		sort.Strings(outcome.BlockingNames)
		outcome.Reason = fmt.Sprintf("pre-merge checks blocked: %s", strings.Join(outcome.BlockingNames, ", "))
	}
	return outcome, nil
}

// PreMergeChecksReason is the canonical Reason prefix written onto preserved
// landings whose preservation was triggered by the pre-merge checks gate.
// Callers (status classifiers, dashboards) match on this prefix to bucket
// pre-merge-checks misses apart from generic merge conflicts or gate failures.
const PreMergeChecksReason = "pre-merge checks blocked"

// AppendPreMergeChecksEvents records one bead event per honoured bypass
// (kind=checks-bypass) and, when blocked, one event per blocking check
// (kind=checks-blocked). Best-effort: append failures are returned as the
// first error encountered so callers can decide whether to surface or log.
//
// actor and source are forwarded onto every appended event so the audit
// trail attributes the gate decision to the right worker / loop session.
func AppendPreMergeChecksEvents(store BeadEventAppender, beadID string, outcome *PreMergeChecksOutcome, actor, source string, now time.Time) error {
	if store == nil || outcome == nil {
		return nil
	}
	var firstErr error
	for _, e := range outcome.Bypassed {
		body := fmt.Sprintf("name=%s\nreason=%s", e.Name, e.Reason)
		if e.Bead != "" {
			body += "\nbead=" + e.Bead
		}
		ev := bead.BeadEvent{
			Kind:      "checks-bypass",
			Summary:   fmt.Sprintf("pre-merge check %q bypassed", e.Name),
			Body:      body,
			Actor:     actor,
			Source:    source,
			CreatedAt: now,
		}
		if err := store.AppendEvent(beadID, ev); err != nil && firstErr == nil {
			firstErr = err
		}
	}
	if outcome.Blocked {
		for _, r := range outcome.Results {
			if r.Status != checks.StatusBlock && r.Status != checks.StatusError {
				continue
			}
			body := fmt.Sprintf("name=%s\nstatus=%s", r.Name, r.Status)
			if r.Message != "" {
				body += "\nmessage=" + r.Message
			}
			ev := bead.BeadEvent{
				Kind:      "checks-blocked",
				Summary:   fmt.Sprintf("pre-merge check %q returned %s", r.Name, r.Status),
				Body:      body,
				Actor:     actor,
				Source:    source,
				CreatedAt: now,
			}
			if err := store.AppendEvent(beadID, ev); err != nil && firstErr == nil {
				firstErr = err
			}
		}
	}
	return firstErr
}

// PreserveAfterPreMergeChecks is the canonical preservation step invoked when
// RunPreMergeChecks returned Blocked=true. It writes refs/ddx/iterations/...
// pointing at the worker's resultRev (so the work survives for later
// inspection) and returns the synthetic LandResult{Status:"preserved"} that
// callers can hand to ApplyLandResultToExecuteBeadResult.
//
// The preserved iteration ref naming follows the existing
// landIterationRef convention so operators see a single ref namespace
// regardless of which gate triggered the preservation.
func PreserveAfterPreMergeChecks(projectRoot string, res *ExecuteBeadResult, outcome *PreMergeChecksOutcome, gitOps OrchestratorGitOps) (*LandResult, error) {
	if outcome == nil || !outcome.Blocked {
		return nil, fmt.Errorf("pre-merge checks: preserve called without blocked outcome")
	}
	if gitOps == nil {
		gitOps = &RealOrchestratorGitOps{}
	}
	ref := PreserveRef(res.BeadID, res.BaseRev)
	if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
		return nil, fmt.Errorf("pre-merge checks: preserving %s: %w", ref, err)
	}
	return &LandResult{
		Status:      "preserved",
		PreserveRef: ref,
		Reason:      outcome.Reason,
	}, nil
}

// preMergeChangedPaths returns the list of paths changed between baseRev and
// resultRev as reported by `git diff --name-only`. Returns (nil, nil) when
// either rev is empty (e.g. a no-changes attempt that should not exercise the
// path-glob filters at all).
func preMergeChangedPaths(projectRoot, baseRev, resultRev string) ([]string, error) {
	if baseRev == "" || resultRev == "" || baseRev == resultRev {
		return nil, nil
	}
	out, err := internalgit.Command(context.Background(), projectRoot, "diff", "--name-only", baseRev, resultRev).CombinedOutput()
	if err != nil {
		return nil, fmt.Errorf("git diff --name-only %s %s: %s: %w", baseRev, resultRev, strings.TrimSpace(string(out)), err)
	}
	var paths []string
	for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
		if p := strings.TrimSpace(line); p != "" {
			paths = append(paths, p)
		}
	}
	return paths, nil
}

func newPreMergeRunID() string {
	var b [4]byte
	_, _ = rand.Read(b[:])
	return time.Now().UTC().Format("20060102T150405") + "-" + hex.EncodeToString(b[:])
}

	Successes         int                  `json:"successes"`
	Failures          int                  `json:"failures"`
	NoReadyWork       bool                 `json:"no_ready_work,omitempty"`
	NoReadyWorkDetail NoReadyWorkBreakdown `json:"no_ready_work_detail,omitempty"`
	LastSuccessAt     time.Time            `json:"last_success_at,omitempty"`
	LastFailureStatus string               `json:"last_failure_status,omitempty"`
	Results           []ExecuteBeadReport  `json:"results,omitempty"`
}

// ExecuteBeadWorker drains the current single-project execution-ready queue.
// It intentionally does not retry a failed/conflicted bead again in the same
// process run; a later operator-driven invocation can create the next attempt.
type ExecuteBeadWorker struct {
	Store               ExecuteBeadLoopStore
	Executor            ExecuteBeadExecutor
	SatisfactionChecker SatisfactionChecker // nil → NoChangesContract default
	// VerificationRunner runs a verification_command parsed out of a
	// no_changes_rationale.txt under NoChangesContract (TD-031 §8.1). When
	// nil, DefaultVerificationCommandRunner is used.
	VerificationRunner VerificationCommandRunner
	Now                func() time.Time
	// Reviewer, when non-nil, is called after every successful merge to
	// validate the commit against the bead's acceptance criteria. When nil,
	// post-merge review is skipped (same behaviour as --no-review).
	Reviewer BeadReviewer

	// ConflictResolver, when non-nil, is called after the 3-way ort auto-merge
	// step fails to recover a preserved iteration. The implementation should
	// attempt a focused conflict-resolution pass (e.g. a cheap-tier agent run
	// with the conflict files and bead AC) and return the new merged tip SHA on
	// success. isBlocking=true signals the conflict requires human judgment
	// (escalating to land_conflict_needs_human); false means failed-but-retriable.
	ConflictResolver func(ctx context.Context, beadID, preserveRef, projectRoot string) (newTip string, isBlocking bool, err error)

	// ComplexityGate, when non-nil, is invoked between RoutePreflight and Claim.
	// It evaluates whether the candidate bead is atomic (proceed to Claim),
	// decomposable (file children, block parent, re-pick), or ambiguous
	// (surface to human triage). When nil, the gate is bypassed and a one-time
	// warning is emitted per Run() invocation. See triage.go and
	// NewComplexityGate for the standard implementation.
	ComplexityGate TriageGate

	// conflictAutoRecoverFn replaces the default landConflictAutoRecover. Set
	// in tests to inject controlled recovery results without a real git repo.
	conflictAutoRecoverFn func(wd, preserveRef string, gitOps LandingGitOps) (string, error)
}

// emitProgress sends a ProgressEvent to runtime.ProgressCh non-blocking.
// If ch is nil or full the event is silently dropped.
func emitProgress(ch chan<- ProgressEvent, evt ProgressEvent) {
	if ch == nil {
		return
	}
	select {
	case ch <- evt:
	default:
	}
}

// newProgressEvent builds a ProgressEvent with a random event_id and current timestamp.
func newProgressEvent(workerID, projectID, beadID, attemptID, harness, model, profile, phase string, phaseSeq int, heartbeat bool, elapsedMS int64) ProgressEvent {
	return ProgressEvent{
		EventID:   "evt-" + randomProgressID(),
		AttemptID: attemptID,
		WorkerID:  workerID,
		ProjectID: projectID,
		BeadID:    beadID,
		Harness:   harness,
		Model:     model,
		Profile:   profile,
		Phase:     phase,
		PhaseSeq:  phaseSeq,
		Heartbeat: heartbeat,
		TS:        time.Now().UTC(),
		ElapsedMS: elapsedMS,
	}
}

func randomProgressID() string {
	return fmt.Sprintf("%x", time.Now().UnixNano())[:8]
}

func (w *ExecuteBeadWorker) Run(ctx context.Context, rcfg config.ResolvedConfig, runtime ExecuteBeadLoopRuntime) (*ExecuteBeadLoopResult, error) {
	if w.Store == nil {
		return nil, fmt.Errorf("execute-bead loop: store is required")
	}
	if w.Executor == nil {
		return nil, fmt.Errorf("execute-bead loop: executor is required")
	}

	now := w.Now
	if now == nil {
		now = time.Now
	}
	assignee := rcfg.Assignee()
	if assignee == "" {
		assignee = "ddx"
	}
	noProgressCooldown := rcfg.NoProgressCooldown()
	if noProgressCooldown <= 0 {
		noProgressCooldown = 6 * time.Hour
	}
	maxNoChangesBeforeClose := rcfg.MaxNoChangesBeforeClose()
	if maxNoChangesBeforeClose <= 0 {
		maxNoChangesBeforeClose = 3
	}
	heartbeatInterval := rcfg.HeartbeatInterval()
	if heartbeatInterval <= 0 {
		heartbeatInterval = bead.HeartbeatInterval
	}
	harness := rcfg.Harness()
	model := rcfg.Model()
	profile := rcfg.Profile()

	result := &ExecuteBeadLoopResult{}
	attempted := make(map[string]struct{})
	// triagedWarned suppresses the one-time boot warning when ComplexityGate is
	// nil. One warning per Run() invocation is enough; the bool resets on the
	// next worker boot.
	triagedWarned := false
	// hookFailed tracks beads whose pre-claim hook failed on first presentation
	// in this run. A bead in hookFailed but not attempted gets one retry: on the
	// second hook failure it moves to attempted so nextCandidate will skip it and
	// the loop can exit gracefully. This prevents infinite spinning when the hook
	// always fails while still allowing transient hook failures to be retried.
	hookFailed := make(map[string]struct{})

	emit := func(eventType string, data map[string]any) {
		writeLoopEvent(runtime.EventSink, runtime.SessionID, eventType, data, now().UTC())
	}

	emit("loop.start", map[string]any{
		"worker_id":    runtime.WorkerID,
		"project_root": runtime.ProjectRoot,
		"harness":      harness,
		"model":        model,
		"session_id":   runtime.SessionID,
		"assignee":     assignee,
		"once":         runtime.Once,
	})
	// exitReason is populated as the loop exits to surface a structured reason
	// in the loop.end event (ddx-dc157075 AC #4). Recognized values: "sigterm",
	// "sigint", "fatal_config", "once_complete", "explicit_poll_zero". The
	// "providers_exhausted" slot is reserved for ddx-aede917d (quota pause).
	exitReason := ""
	defer func() {
		emit("loop.end", map[string]any{
			"attempts":            result.Attempts,
			"successes":           result.Successes,
			"failures":            result.Failures,
			"last_failure_status": result.LastFailureStatus,
			"exit_reason":         exitReason,
		})
	}()

	for {
		// Respect context cancellation between iterations. Without this check,
		// a Stop() request (which cancels ctx) would only take effect during
		// the idle poll sleep — the loop would happily claim the next ready
		// bead as soon as the current Execute returned, ignoring the cancel.
		if err := ctx.Err(); err != nil {
			if exitReason == "" {
				switch err {
				case context.Canceled:
					exitReason = "sigint"
				case context.DeadlineExceeded:
					exitReason = "sigterm"
				default:
					exitReason = "context_cancelled"
				}
			}
			return result, err
		}

		candidate, skips, ok, err := w.nextCandidate(attempted, runtime.LabelFilter, runtime.TargetBeadID)
		if err != nil {
			exitReason = "fatal_config"
			return result, err
		}
		// Diagnostic: when nextCandidate selected a lower-priority bead while
		// at least one higher-priority bead was skipped, emit a structured
		// picker.priority_skip event naming each skipped bead and the reason
		// (ddx-9d55601f AC #4). Without this surface, an operator who sees a
		// worker claim a P2 while P0s sit in `ddx bead ready` cannot tell
		// whether the picker has a bug, the P0s are filtered upstream, or a
		// label filter is in play.
		if ok {
			emitPickerPrioritySkips(emit, candidate, skips)
		}
		if !ok {
			if result.Attempts == 0 {
				result.NoReadyWork = true
				if diag, ok := w.Store.(readyDiagnoser); ok {
					if breakdown, bErr := diag.ReadyExecutionBreakdown(); bErr == nil {
						result.NoReadyWorkDetail = NoReadyWorkBreakdown{
							SkippedEpics:       breakdown.SkippedEpics,
							SkippedOnCooldown:  breakdown.SkippedOnCooldown,
							SkippedNotEligible: breakdown.SkippedNotEligible,
							SkippedSuperseded:  breakdown.SkippedSuperseded,
							NextRetryAfter:     breakdown.NextRetryAfter,
						}
					}
				}
			}
			if runtime.PollInterval <= 0 {
				// Legacy "drain-and-exit" semantics: operator either passed
				// --once (handled at end-of-iteration) or explicitly set
				// --poll-interval=0. ddx-dc157075: with default --poll-interval
				// flipped to 30s in CLI/server, this path now only fires for
				// the explicit opt-out case.
				if runtime.Once {
					exitReason = "once_complete"
				} else {
					exitReason = "explicit_poll_zero"
				}
				return result, nil
			}
			// --once with poll-interval > 0: an empty queue still means there
			// is no work to pick, and --once explicitly asked for at-most-one.
			// Returning here preserves the operator-visible "drain and stop"
			// semantics of --once even when the long-running default applies.
			if runtime.Once {
				exitReason = "once_complete"
				return result, nil
			}
			// Long-running drain (poll-interval > 0): emit a transient
			// "no_ready_work" event so server-managed workers can surface this
			// as an idle substate (ddx-dc157075 AC #5) instead of treating it
			// as terminal.
			emit("loop.idle", map[string]any{
				"reason":        "no_ready_work",
				"poll_interval": runtime.PollInterval.String(),
			})
			// Surface the idle substate via the progress channel so server-side
			// drainProgress can flip WorkerRecord.Substate to "idle" without
			// reading the JSONL event log. Phase="loop.idle" is treated as a
			// substate signal, not a per-bead attempt phase.
			emitProgress(runtime.ProgressCh, ProgressEvent{
				EventID:   "evt-" + randomProgressID(),
				WorkerID:  runtime.WorkerID,
				ProjectID: runtime.ProjectRoot,
				Phase:     "loop.idle",
				Heartbeat: true,
				TS:        now().UTC(),
				Message:   "no_ready_work",
			})
			// Reset per-Run attempted/hookFailed maps before sleeping
			// (ddx-dc157075 AC #2). Without this reset, beads attempted earlier
			// in this Run remain filtered out of nextCandidate forever, so the
			// "attempted-once = exit" trap reasserts itself: a bead whose
			// cooldown has expired since its last attempt would never be
			// re-picked by the same long-running worker.
			for k := range attempted {
				delete(attempted, k)
			}
			for k := range hookFailed {
				delete(hookFailed, k)
			}
			if err := sleepOrWake(ctx, runtime.PollInterval, runtime.WakeCh); err != nil {
				if exitReason == "" {
					switch err {
					case context.Canceled:
						exitReason = "sigint"
					case context.DeadlineExceeded:
						exitReason = "sigterm"
					default:
						exitReason = "context_cancelled"
					}
				}
				return result, err
			}
			continue
		}

		// Found a candidate: clear any "idle" substate set on the previous
		// no-candidate iteration (ddx-dc157075 AC #5).
		emitProgress(runtime.ProgressCh, ProgressEvent{
			EventID:   "evt-" + randomProgressID(),
			WorkerID:  runtime.WorkerID,
			ProjectID: runtime.ProjectRoot,
			BeadID:    candidate.ID,
			Phase:     "loop.active",
			Heartbeat: true,
			TS:        now().UTC(),
		})

		// Pre-claim hook: fetch origin + verify ancestry before claiming.
		// On error the bead is skipped for this iteration; the loop
		// continues (ctx is not cancelled). The bead is NOT added to
		// attempted on the FIRST failure so a transient hook failure (e.g.
		// diverged branch) allows a retry on the next iteration. On a
		// SECOND failure for the same bead in the same run it is moved into
		// attempted so nextCandidate will skip it, preventing an infinite
		// loop when the hook always fails.
		if runtime.PreClaimHook != nil {
			if hookErr := runtime.PreClaimHook(ctx); hookErr != nil {
				if runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log, "pre-claim hook: %v (skipping %s)\n", hookErr, candidate.ID)
				}
				emit("preclaim.skipped", map[string]any{
					"bead_id": candidate.ID,
					"reason":  hookErr.Error(),
				})
				if _, alreadyFailed := hookFailed[candidate.ID]; alreadyFailed {
					// Second failure in this run: stop retrying this bead.
					attempted[candidate.ID] = struct{}{}
				} else {
					hookFailed[candidate.ID] = struct{}{}
				}
				continue
			}
		}

		attempted[candidate.ID] = struct{}{}

		// Routing preflight gate (FEAT-006 D3, ddx-98e6e9ef): consult the
		// upstream typed-incompatibility surface BEFORE claiming. If the
		// configured (harness, model) cannot serve the bead, exit the loop
		// with a worker-level failure record — no claim, no executor
		// invocation, no tier-attempt event burn.
		if runtime.RoutePreflight != nil {
			if rerr := runtime.RoutePreflight(ctx, harness, model); rerr != nil {
				detail := fmt.Sprintf("routing preflight rejected (harness=%s model=%s): %s",
					harness, model, rerr.Error())
				if runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log, "routing preflight: %s (skipping %s)\n",
						detail, candidate.ID)
				}
				emit("preflight.rejected", map[string]any{
					"bead_id": candidate.ID,
					"harness": harness,
					"model":   model,
					"reason":  rerr.Error(),
				})
				report := ExecuteBeadReport{
					BeadID:           candidate.ID,
					Status:           ExecuteBeadStatusExecutionFailed,
					Detail:           detail,
					Harness:          harness,
					Model:            model,
					Disrupted:        true,
					DisruptionReason: "preflight_rejected",
				}
				// ddx-5b3e57f4: a routing preflight rejection is an operator
				// configuration issue (harness/model allow-list mismatch), not
				// evidence the model could not make progress. Mark the report
				// Disrupted and emit the diagnostic event so operators can see
				// disruption rates without parking the bead in a no-progress
				// cooldown.
				emitDisruptionDetected(emit, w.Store, candidate.ID,
					"preflight_rejected", detail, harness, model, assignee, now().UTC())
				result.Attempts++
				result.Failures++
				result.LastFailureStatus = report.Status
				result.Results = append(result.Results, report)
				// ddx-dc157075 AC #3: do NOT abandon the rest of the queue on
				// a single bead's preflight rejection. Continue to the next
				// candidate. If --once was requested we still honour it.
				if runtime.Once {
					exitReason = "once_complete"
					return result, nil
				}
				continue
			}
		}

		// Complexity triage gate (ddx-5bf4ee7e): pre-Claim decomposition check.
		// When the gate is nil, decomposition responsibility shifts to the
		// LLM-driven path inside execute-bead (ddx-b790449b AC5): the agent
		// is prompted to recognize coarse beads, file children, and exit
		// early. The pre-dispatch warning is intentionally suppressed —
		// it is no longer accurate now that decomposition lives downstream.
		if w.ComplexityGate == nil {
			_ = triagedWarned // retained for future re-introduction of a typed gate
		} else {
			shouldClaim, triageErr := w.ComplexityGate(ctx, candidate)
			if triageErr != nil {
				if runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log,
						"triage gate error for %s: %v (skipping)\n", candidate.ID, triageErr)
				}
				emit("triage.error", map[string]any{
					"bead_id": candidate.ID,
					"reason":  triageErr.Error(),
				})
				// A gate error does not count as an attempt; re-pick next candidate.
				continue
			}
			if !shouldClaim {
				if runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log,
						"triage: skipped dispatch of %s (classified as non-atomic)\n", candidate.ID)
				}
				emit("triage.skipped", map[string]any{"bead_id": candidate.ID})
				continue
			}
		}

		if err := w.Store.Claim(candidate.ID, assignee); err != nil {
			// Another worker won the race for this bead. Emit a structured
			// claim_race event so concurrent-worker losses are observable

package agent

// checks_premerge_e2e_test.go — end-to-end coverage for the pre-merge checks
// gate wired into the execute-bead loop's land-back step.
//
// Each test boots a real temp git repo + .ddx tracker store, drops a fixture
// .ddx/checks/dummy-fail.yaml whose script always returns status=block, and
// drives SubmitWithPreMergeChecks against a synthesised worker
// ExecuteBeadResult to assert the documented contract:
//
//	Test 1 — block fixture causes preserve, submit not called, evidence and
//	         events recorded.
//	Test 2 — block fixture + checks_bypass annotation causes submit to run
//	         and a checks-bypass event to be recorded.

import (
	"context"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// preMergeRepo is a focused version of landTestRepo specialised for these
// pre-merge gate tests: it owns a .ddx tracker store as well as the git repo,
// so we can create beads and read events without any extra setup.
type preMergeRepo struct {
	t       *testing.T
	dir     string
	store   *bead.Store
	baseSHA string
}

func newPreMergeRepo(t *testing.T) *preMergeRepo {
	t.Helper()
	dir := t.TempDir()
	r := &preMergeRepo{t: t, dir: dir}
	r.runGit("init", "-b", "main")
	r.runGit("config", "user.name", "Test")
	r.runGit("config", "user.email", "test@test.local")
	if err := os.WriteFile(filepath.Join(dir, "README.md"), []byte("# pre-merge\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	r.runGit("add", "-A")
	r.runGit("commit", "-m", "init")
	r.baseSHA = strings.TrimSpace(r.runGit("rev-parse", "HEAD"))

	r.store = bead.NewStore(filepath.Join(dir, ".ddx"))
	if err := r.store.Init(); err != nil {
		t.Fatalf("store init: %v", err)
	}
	return r
}

func (r *preMergeRepo) runGit(args ...string) string {
	r.t.Helper()
	cmd := exec.Command("git", append([]string{"-C", r.dir}, args...)...)
	out, err := cmd.CombinedOutput()
	if err != nil {
		r.t.Fatalf("git %s: %s: %v", strings.Join(args, " "), string(out), err)
	}
	return string(out)
}

// commitNoOp creates a one-file commit reachable via the object store but not
// any branch, returning its SHA. Used as the worker's resultRev so the gate
// has a real (baseRev → resultRev) range to diff against.
func (r *preMergeRepo) commitNoOp() string {
	r.t.Helper()
	wt, err := os.MkdirTemp("", "premerge-wt-*")
	if err != nil {
		r.t.Fatal(err)
	}
	_ = os.RemoveAll(wt)
	r.runGit("worktree", "add", "--detach", wt, r.baseSHA)
	defer func() {
		r.runGit("worktree", "remove", "--force", wt)
		_ = os.RemoveAll(wt)
	}()
	if err := os.WriteFile(filepath.Join(wt, "noop.txt"), []byte("hello\n"), 0o644); err != nil {
		r.t.Fatal(err)
	}
	cmd := exec.Command("git", "-C", wt, "add", "-A")
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git add: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt,
		"-c", "user.name=Test", "-c", "user.email=test@test.local",
		"commit", "-m", "noop")
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git commit: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt, "rev-parse", "HEAD")
	out, err := cmd.CombinedOutput()
	if err != nil {
		r.t.Fatalf("git rev-parse: %s: %v", string(out), err)
	}
	return strings.TrimSpace(string(out))
}

// writeDummyFailCheck drops a deterministic check definition that always
// writes status=block and exits 0 (so the runner's failure mode is "result
// file says block", not "command crashed").
func (r *preMergeRepo) writeDummyFailCheck() {
	r.t.Helper()
	checkDir := filepath.Join(r.dir, ".ddx", "checks")
	if err := os.MkdirAll(checkDir, 0o755); err != nil {
		r.t.Fatal(err)
	}
	yaml := `name: dummy-fail
when: pre_merge
command: |
  cat > "${EVIDENCE_DIR}/${CHECK_NAME}.json" <<EOF
  {"status":"block","message":"dummy-fail fixture: always blocks"}
  EOF
`
	if err := os.WriteFile(filepath.Join(checkDir, "dummy-fail.yaml"), []byte(yaml), 0o644); err != nil {
		r.t.Fatal(err)
	}
}

// makeBead creates an open bead in the tracker and returns it. extra is
// merged into bead.Extra so callers can attach a checks_bypass annotation.
func (r *preMergeRepo) makeBead(id string, extra map[string]any) *bead.Bead {
	r.t.Helper()
	b := &bead.Bead{
		ID:     id,
		Title:  "fixture bead for pre-merge checks",
		Status: bead.StatusOpen,
		Labels: []string{"phase:2", "area:checks"},
		Extra:  extra,
	}
	if err := r.store.Create(b); err != nil {
		r.t.Fatalf("create bead: %v", err)
	}
	got, err := r.store.Get(id)
	if err != nil {
		r.t.Fatalf("get bead: %v", err)
	}
	return got
}

// readEvents reads the bead's appended events via the store's Events helper.
func (r *preMergeRepo) readEvents(id string) []bead.BeadEvent {
	r.t.Helper()
	evs, err := r.store.Events(id)
	if err != nil {
		r.t.Fatalf("read events: %v", err)
	}
	return evs
}

// TestSubmitWithPreMergeChecks_DummyFailAbortsMerge covers AC #4: a fixture
// dummy-fail check causes merge abort, the worker's resultRev is preserved
// under refs/ddx/iterations/, the per-check evidence file is on disk, and a
// checks-blocked event is appended to the bead.
func TestSubmitWithPreMergeChecks_DummyFailAbortsMerge(t *testing.T) {
	r := newPreMergeRepo(t)
	r.writeDummyFailCheck()
	b := r.makeBead("pmc-block-001", nil)
	resultSHA := r.commitNoOp()

	runID := time.Now().UTC().Format("20060102T150405") + "-pmcblk1"
	res := &ExecuteBeadResult{
		BeadID:       b.ID,
		BaseRev:      r.baseSHA,
		ResultRev:    resultSHA,
		ExecutionDir: filepath.Join(".ddx", "executions", runID),
	}

	submitCalled := false
	submit := func(req LandRequest) (*LandResult, error) {
		submitCalled = true
		return &LandResult{Status: "landed", NewTip: req.ResultRev}, nil
	}

	land, outcome, err := SubmitWithPreMergeChecks(
		context.Background(), r.dir, b, res,
		submit, r.store, "ddx-test-actor", "test-source", nil,
	)
	if err != nil {
		t.Fatalf("SubmitWithPreMergeChecks: %v", err)
	}
	if submitCalled {
		t.Fatalf("submit must NOT be called when pre-merge checks block (AC #4)")
	}
	if outcome == nil || !outcome.Blocked {
		t.Fatalf("outcome must report Blocked=true; got %+v", outcome)
	}
	if !sliceContains(outcome.BlockingNames, "dummy-fail") {
		t.Fatalf("BlockingNames must contain dummy-fail; got %v", outcome.BlockingNames)
	}
	if land == nil || land.Status != "preserved" {
		t.Fatalf("LandResult must be preserved; got %+v", land)
	}
	if land.PreserveRef == "" || !strings.HasPrefix(land.PreserveRef, "refs/ddx/iterations/"+b.ID+"/") {
		t.Fatalf("PreserveRef must follow refs/ddx/iterations/<bead-id>/ convention; got %q", land.PreserveRef)
	}

	// Worktree-preservation invariant (AC #2 + #6): the preserve ref must
	// resolve to the worker's resultSHA in the real git object store.
	got := strings.TrimSpace(r.runGit("rev-parse", land.PreserveRef))
	if got != resultSHA {
		t.Fatalf("preserve ref resolves to %s; want resultSHA %s", got, resultSHA)
	}

	// Evidence file (AC #6): checks runner must have written a JSON result
	// file at <projectRoot>/<execDir>/checks/dummy-fail.json.
	evidenceFile := filepath.Join(r.dir, res.ExecutionDir, "checks", "dummy-fail.json")
	data, readErr := os.ReadFile(evidenceFile)
	if readErr != nil {
		t.Fatalf("evidence file missing at %s: %v", evidenceFile, readErr)
	}
	if !strings.Contains(string(data), `"status":"block"`) {
		t.Fatalf("evidence file does not show status=block: %s", string(data))
	}

	// Event recorded (AC #4): one checks-blocked event for dummy-fail.
	evs := r.readEvents(b.ID)
	var blockedEvents []bead.BeadEvent
	for _, e := range evs {
		if e.Kind == "checks-blocked" {
			blockedEvents = append(blockedEvents, e)
		}
	}
	if len(blockedEvents) != 1 {
		t.Fatalf("expected exactly one checks-blocked event; got %d (events=%+v)", len(blockedEvents), evs)
	}
	if !strings.Contains(blockedEvents[0].Body, "name=dummy-fail") {
		t.Fatalf("checks-blocked event body should name dummy-fail; got %q", blockedEvents[0].Body)
	}
}

// TestSubmitWithPreMergeChecks_BypassAllowsMerge covers AC #5: the same
// fixture + a checks_bypass annotation skips the named check, submit runs
// normally, and a checks-bypass event with the documented reason is recorded.
func TestSubmitWithPreMergeChecks_BypassAllowsMerge(t *testing.T) {
	r := newPreMergeRepo(t)
	r.writeDummyFailCheck()
	b := r.makeBead("pmc-bypass-001", map[string]any{
		"checks_bypass": []any{
			map[string]any{
				"name":   "dummy-fail",
				"reason": "fixture: dummy-fail is always-block by design; bypassed in this test scenario",
				"bead":   "pmc-bypass-001",
			},
		},
	})
	resultSHA := r.commitNoOp()

	runID := time.Now().UTC().Format("20060102T150405") + "-pmcbyp1"
	res := &ExecuteBeadResult{
		BeadID:       b.ID,
		BaseRev:      r.baseSHA,
		ResultRev:    resultSHA,
		ExecutionDir: filepath.Join(".ddx", "executions", runID),
	}

	submitCalled := false
	submit := func(req LandRequest) (*LandResult, error) {
		submitCalled = true
		if req.BeadID != b.ID {
			t.Fatalf("submit got unexpected bead %q; want %q", req.BeadID, b.ID)
		}
		return &LandResult{Status: "landed", NewTip: req.ResultRev}, nil
	}

	land, outcome, err := SubmitWithPreMergeChecks(
		context.Background(), r.dir, b, res,
		submit, r.store, "ddx-test-actor", "test-source", nil,
	)
	if err != nil {
		t.Fatalf("SubmitWithPreMergeChecks: %v", err)
	}
	if !submitCalled {
		t.Fatalf("submit MUST be called when the only blocking check is bypassed (AC #5)")
	}
	if outcome == nil {
		t.Fatalf("outcome required, got nil")
	}
	if outcome.Blocked {
		t.Fatalf("outcome must not be Blocked when only check is bypassed; got %+v", outcome)
	}
	if len(outcome.Bypassed) != 1 || outcome.Bypassed[0].Name != "dummy-fail" {
		t.Fatalf("Bypassed slice must record dummy-fail; got %+v", outcome.Bypassed)
	}
	if land == nil || land.Status != "landed" {
		t.Fatalf("LandResult must reflect the underlying submit result; got %+v", land)
	}

	// Bypass event recorded with the operator-supplied reason.
	evs := r.readEvents(b.ID)
	var bypassEvents []bead.BeadEvent
	for _, e := range evs {
		if e.Kind == "checks-bypass" {
			bypassEvents = append(bypassEvents, e)
		}
	}
	if len(bypassEvents) != 1 {
		t.Fatalf("expected exactly one checks-bypass event; got %d (events=%+v)", len(bypassEvents), evs)
	}
	if !strings.Contains(bypassEvents[0].Body, "reason=fixture: dummy-fail is always-block") {
		t.Fatalf("checks-bypass event body must echo the operator-supplied reason; got %q", bypassEvents[0].Body)
	}
}

// TestSubmitWithPreMergeChecks_BypassMissingReasonRejected covers the
// "missing reason → bypass rejected loudly" half of AC #3: when the
// annotation has an empty reason, the gate must NOT honour the bypass and
// instead preserve the worker's result (treating the misconfigured bypass as
// a hard preserve, not a silent merge).
func TestSubmitWithPreMergeChecks_BypassMissingReasonRejected(t *testing.T) {
	r := newPreMergeRepo(t)
	r.writeDummyFailCheck()
	b := r.makeBead("pmc-badbypass-001", map[string]any{
		"checks_bypass": []any{
			map[string]any{
				"name":   "dummy-fail",
				"reason": "   ", // whitespace-only counts as missing
			},
		},
	})
	resultSHA := r.commitNoOp()

	runID := time.Now().UTC().Format("20060102T150405") + "-pmcbad1"
	res := &ExecuteBeadResult{
		BeadID:       b.ID,
		BaseRev:      r.baseSHA,
		ResultRev:    resultSHA,
		ExecutionDir: filepath.Join(".ddx", "executions", runID),
	}

	submitCalled := false
	submit := func(req LandRequest) (*LandResult, error) {
		submitCalled = true
		return &LandResult{Status: "landed"}, nil
	}

	land, _, err := SubmitWithPreMergeChecks(
		context.Background(), r.dir, b, res,
		submit, r.store, "ddx-test-actor", "test-source", nil,
	)
	if err != nil {
		t.Fatalf("SubmitWithPreMergeChecks: %v", err)
	}
	if submitCalled {
		t.Fatalf("submit MUST NOT be called when bypass annotation is invalid (AC #3)")
	}
	if land == nil || land.Status != "preserved" {
		t.Fatalf("LandResult must be preserved when bypass is rejected; got %+v", land)
	}
	if !strings.Contains(land.Reason, "checks_bypass") {
		t.Fatalf("preserve reason must mention the rejected checks_bypass; got %q", land.Reason)
	}
}

func sliceContains(haystack []string, needle string) bool {
	for _, s := range haystack {
		if s == needle {
			return true
		}
	}
	return false
}

	// spawning a new worker. This is the parent's responsibility.
	agent.RecoverOrphans(gitOps, projectRoot, beadID)

	// Worker step: run the agent in an isolated worktree.
	res, err := agent.ExecuteBeadWithConfig(cmd.Context(), projectRoot, beadID, rcfg, runtime, gitOps)
	if err != nil && res == nil {
		return err
	}

	// Orchestrator step: land the result (ff or merge → push, gate eval,
	// preserve). Always run when we have a result — the orchestrator handles
	// all cases including no-changes and error (agent failed with no commits).
	//
	// Single-bead CLI is strictly serial (no sibling workers in this
	// process), so we can wire the LandingAdvancer to call Land() directly
	// without going through a per-project coordinator goroutine. Tests may
	// inject a custom advancer via f.executeBeadLandingAdvancerOverride.
	if res != nil {
		var advancer func(r *agent.ExecuteBeadResult) (*agent.LandResult, error)
		if f.executeBeadLandingAdvancerOverride != nil {
			advancer = f.executeBeadLandingAdvancerOverride
		} else {
			landingGitOps := landingGitOpsFromFactory(f)
			advancer = func(r *agent.ExecuteBeadResult) (*agent.LandResult, error) {
				return agent.Land(projectRoot, agent.BuildLandRequestFromResult(projectRoot, r), landingGitOps)
			}
		}
		landingOpts := agent.BeadLandingOptions{
			NoMerge:         noMerge,
			LandingAdvancer: advancer,
		}

		// Wire required execution gates: when the worker manifest declares
		// governing IDs, gate-eval them in an ephemeral worktree at ResultRev
		// before LandBeadResult decides merge vs preserve. The original
		// worker worktree was cleaned up by ExecuteBead, so we pin ResultRev
		// to a transient ref and check it out into a temp worktree for the
		// duration of gate evaluation.
		if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
			wt, ids, cleanup, ctxErr := agent.BuildLandingGateContext(projectRoot, res, gitOps)
			if ctxErr != nil {
				// Soft-fail: log and skip gate eval rather than abort the land.
				fmt.Fprintf(os.Stderr, "ddx: warning: gate-context setup failed: %v (skipping required-gate eval)\n", ctxErr)
			} else if wt != "" {
				defer cleanup()
				landingOpts.WtPath = wt
				landingOpts.GovernIDs = ids
				landingOpts.ChecksArtifactPath = filepath.Join(projectRoot, res.ExecutionDir, "checks.json")
				landingOpts.ChecksArtifactRel = filepath.Join(res.ExecutionDir, "checks.json")
			}
		}

		if landing, landErr := agent.LandBeadResult(projectRoot, res, orchestratorGitOps, landingOpts); landErr == nil {
			agent.ApplyLandingToResult(res, landing)
		} else if err == nil {
			err = landErr
		}
	}

	if err != nil {
		_ = writeExecuteBeadResult(cmd, res, asJSON)
		return err
	}

	return writeExecuteBeadResult(cmd, res, asJSON)
}

