// LandBeadResult is the parent-side orchestrator. It receives a completed worker
// result and decides whether to merge, preserve, or report no-changes. All
// Merge, UpdateRef, gate evaluation, and preserve-ref management live here.
// The worker (ExecuteBead) must not call any of these operations.
//
// Outcome rules:
//   - ResultRev == BaseRev → "no-changes" (agent made no commits)
//   - ExitCode != 0 with commits → "preserved" (agent failed but left output)
//   - Gate failed → "preserved"
//   - NoMerge → "preserved"
//   - Default → attempt merge; on conflict → "preserved"
func LandBeadResult(projectRoot string, res *ExecuteBeadResult, gitOps OrchestratorGitOps, opts BeadLandingOptions) (*BeadLandingResult, error) {
	landing := &BeadLandingResult{}

	// Agent failed with no commits: report as error (not no-changes).
	// Prefer res.Reason (e.g. HeadRev failure set by worker) over res.Error
	// (agent error) so the primary context failure is surfaced as the reason.
	if res.ExitCode != 0 && res.ResultRev == res.BaseRev {
		landing.Outcome = "error"
		switch {
		case res.Reason != "":
			landing.Reason = res.Reason
		case res.Error != "":
			landing.Reason = res.Error
		default:
			landing.Reason = "agent execution failed"
		}
		return landing, nil
	}

	// No changes from the worker: nothing to land.
	if res.ResultRev == res.BaseRev {
		if res.Outcome == ExecuteBeadOutcomeTaskNoEvidence || res.FailureMode == FailureModeNoEvidenceProduced {
			landing.Outcome = "no-evidence"
			if res.Reason != "" {
				landing.Reason = res.Reason
			} else if res.Error != "" {
				landing.Reason = res.Error
			} else {
				landing.Reason = "agent exited without a commit or no_changes_rationale.txt"
			}
			return landing, nil
		}
		landing.Outcome = "no-changes"
		if res.NoChangesRationale != "" {
			landing.Reason = res.NoChangesRationale
		} else {
			landing.Reason = "agent made no commits"
		}
		return landing, nil
	}

	// Agent failed but produced commits: preserve without attempting merge.
	if res.ExitCode != 0 {
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
			return nil, fmt.Errorf("preserving result ref: %w", err)
		}
		landing.Outcome = "preserved"
		landing.PreserveRef = ref
		landing.Reason = "agent execution failed"
		return landing, nil
	}

	// Evaluate required gates when a worktree path and governing IDs are
	// provided. EvaluateRequiredGatesForResult is the canonical helper —
	// shared with upstream callers that want gate eval before submitting
	// through the coordinator. It mutates res.GateResults / RequiredExecSummary
	// / RatchetEvidence / RatchetSummary / ChecksFile in place; we mirror the
	// outputs onto landing so ApplyLandingToResult can copy them back later
	// without losing the existing landing.* contract.
	anyGateFailed, anyRatchetFailed, gateErr := EvaluateRequiredGatesForResult(
		opts.WtPath, opts.GovernIDs, res, projectRoot,
		opts.ChecksArtifactPath, opts.ChecksArtifactRel,
	)
	if gateErr != nil {
		return nil, gateErr
	}
	gateResults := res.GateResults
	landing.GateResults = gateResults
	landing.RequiredExecSummary = res.RequiredExecSummary
	landing.RatchetEvidence = res.RatchetEvidence
	landing.RatchetSummary = res.RatchetSummary
	landing.ChecksFile = res.ChecksFile

	// Gate failed: preserve instead of merging. Ratchet misses get a
	// dedicated reason so status/failure_mode classifiers can distinguish
	// them from generic command failures.
	if anyGateFailed {
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
			return nil, fmt.Errorf("preserving result ref: %w", err)
		}
		landing.Outcome = "preserved"
		landing.PreserveRef = ref
		if anyRatchetFailed {
			landing.Reason = RatchetPreserveReason
		} else {
			landing.Reason = "post-run checks failed"
		}
		return landing, nil
	}

	// --no-merge: preserve unconditionally.
	if opts.NoMerge {
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
			return nil, fmt.Errorf("preserving result ref: %w", err)
		}
		landing.Outcome = "preserved"
		landing.PreserveRef = ref
		landing.Reason = "--no-merge specified"
		return landing, nil
	}

	// Default: land the worker's commits on the target branch. When a
	// LandingAdvancer is provided (server coordinator / --local coordinator)
	// it runs the fetch → (ff or merge) → push sequence serialized per
	// projectRoot. When no advancer is provided, LandBeadResult falls back
	// to preserving the result under refs/ddx/iterations/ — the interactive
	// single-bead CLI path, which intentionally does NOT auto-advance the
	// target branch (the operator moves the ref themselves).
	if opts.LandingAdvancer != nil {
		land, landErr := opts.LandingAdvancer(res)
		if landErr != nil {
			return nil, fmt.Errorf("land advancer: %w", landErr)
		}
		switch land.Status {
		case "landed":
			landing.Outcome = "merged"
			if land.Merged {
				landing.Reason = "merged onto current tip"
			}
			if land.NewTip != "" {
				res.ResultRev = land.NewTip
			}
			if land.PushFailed {
				landing.Reason = PushFailedReasonPrefix + " " + land.PushError
			}
		case "preserved":
			landing.Outcome = "preserved"
			landing.PreserveRef = land.PreserveRef
			landing.Reason = land.Reason
		case "no-changes":
			landing.Outcome = "no-changes"
			landing.Reason = land.Reason
		default:
			landing.Outcome = "preserved"
			landing.Reason = "unknown land status: " + land.Status
		}
		return landing, nil
	}

	// No advancer: preserve under refs/ddx/iterations/ as a safe fallback.
	ref := PreserveRef(res.BeadID, res.BaseRev)
	if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
		return nil, fmt.Errorf("preserving result ref (no land advancer): %w", err)
	}
	landing.Outcome = "preserved"
	landing.PreserveRef = ref
	landing.Reason = "no land advancer configured"
	return landing, nil
}

// ApplyLandingToResult merges a BeadLandingResult's fields into an
// ExecuteBeadResult so callers can output a single unified record. It
// overwrites Outcome, Status, Detail, Reason, PreserveRef, GateResults,
// RequiredExecSummary, and ChecksFile based on the landing decision.
func ApplyLandingToResult(res *ExecuteBeadResult, landing *BeadLandingResult) {
	res.Outcome = landing.Outcome
	res.Reason = landing.Reason
	res.PreserveRef = landing.PreserveRef
	res.GateResults = landing.GateResults
	res.RequiredExecSummary = landing.RequiredExecSummary
	res.ChecksFile = landing.ChecksFile
	res.RatchetEvidence = landing.RatchetEvidence

// Package try — Attempt is the C2 shell that wraps the existing
// agent.ExecuteBeadWithConfig + agent.LandBeadResult + (optional)
// agent.DefaultBeadReviewer pipeline and returns a try.Outcome via the C1
// ToOutcome adapter. It has no production callers at end of C2; the
// orchestrator continues to drive the legacy executor directly. Callers
// migrate in C3+.
package try

import (
	"context"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
)

// AttemptOpts bundles the knobs Attempt needs to drive the legacy
// ExecuteBeadWithConfig + LandBeadResult + DefaultBeadReviewer pipeline.
//
// Tests inject Executor to supply a canned ExecuteBeadReport without
// touching git or a real harness. When Executor is non-nil it short-circuits
// the legacy pipeline entirely; the remaining fields are ignored.
type AttemptOpts struct {
	// Executor is an optional injection seam. When non-nil, Attempt delegates
	// to it instead of calling ExecuteBeadWithConfig + LandBeadResult.
	Executor agent.ExecuteBeadExecutor

	// ProjectRoot is the repo the bead executes in.
	ProjectRoot string

	// Rcfg is the resolved harness/model/profile config for the attempt.
	Rcfg config.ResolvedConfig

	// Runtime carries non-durable injection seams (BeadEvents, AgentRunner, …).
	Runtime agent.ExecuteBeadRuntime

	// GitOps is the worker-side git surface (worktree add/remove, head, …).
	GitOps agent.GitOps

	// OrchestratorGitOps is the parent-side git surface (UpdateRef).
	OrchestratorGitOps agent.OrchestratorGitOps

	// LandingOpts controls how LandBeadResult lands a completed worker result.
	LandingOpts agent.BeadLandingOptions

	// Reviewer, when non-nil, is invoked after a successful merge to validate
	// the commit against the bead's AC. When nil, post-merge review is skipped.
	Reviewer agent.BeadReviewer
}

// Attempt runs one bead attempt and returns a try.Outcome.
//
// When opts.Executor is non-nil, Attempt delegates to it and converts the
// returned ExecuteBeadReport via ToOutcome — the path covered by
// TestAttempt_WrapsLegacyExecutor.
//
// Otherwise Attempt drives the legacy pipeline:
//
//  1. agent.ExecuteBeadWithConfig — run the agent in an isolated worktree.
//  2. agent.LandBeadResult — merge or preserve, evaluate gates.
//  3. opts.Reviewer.ReviewBead (best effort) — optional post-merge review.
//
// The store argument is reserved for the C3+ migration where Attempt will
// own bead-tracker bookkeeping (claim, heartbeat, close). At C2 it is
// accepted but not yet used; the legacy loop still owns those calls.
func Attempt(ctx context.Context, store agent.ExecuteBeadLoopStore, beadID string, opts AttemptOpts) (Outcome, error) {
	_ = store // reserved for C3+ migration; legacy loop still owns store I/O.

	if opts.Executor != nil {
		report, err := opts.Executor.Execute(ctx, beadID)
		if err != nil {
			out := ToOutcome(report)
			if out.BeadID == "" {
				out.BeadID = beadID
			}
			return out, err
		}
		out := ToOutcome(report)
		if out.BeadID == "" {
			out.BeadID = beadID
		}
		return out, nil
	}

	res, execErr := agent.ExecuteBeadWithConfig(ctx, opts.ProjectRoot, beadID, opts.Rcfg, opts.Runtime, opts.GitOps)
	if execErr != nil && res == nil {
		return Outcome{BeadID: beadID}, execErr
	}

	if res != nil {
		landing, landErr := agent.LandBeadResult(opts.ProjectRoot, res, opts.OrchestratorGitOps, opts.LandingOpts)
		if landErr == nil {
			agent.ApplyLandingToResult(res, landing)
		} else if execErr == nil {
			execErr = landErr
		}
	}

	if opts.Reviewer != nil && res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
		// C3 (ddx-a921ff01): drive the full post-merge review state machine
		// — verdict events, close-on-APPROVE, reopen-on-REQUEST_CHANGES /
		// BLOCK, triage callout — via the extracted RunPostMergeReview that
		// replaces the 180-line inline review block in execute_bead_loop.go.
		// Store errors are swallowed at this layer because the legacy loop
		// (which currently owns claim/heartbeat/close bookkeeping) handles
		// them via handleOutcomeStoreError; the C3 shell predates that
		// migration (C7) and so cannot route the same way.
		report := agent.ExecuteBeadReport{
			BeadID:      beadID,
			AttemptID:   res.AttemptID,
			Harness:     res.Harness,
			Provider:    res.Provider,
			Model:       res.Model,
			ActualPower: res.ActualPower,
			SessionID:   res.SessionID,
			BaseRev:     res.BaseRev,
			ResultRev:   res.ResultRev,
		}
		_ = agent.RunPostMergeReview(ctx, agent.PostMergeReviewInput{
			Bead:        bead.Bead{ID: beadID},
